// Constantes de validación
export const CART_LIMITS = {
  MAX_ITEMS: 10,
  MAX_WEIGHT_KG: 15
};

// Calcula la distancia en línea recta entre dos puntos (Fórmula de Haversine)
export const calcularDistancia = (lat1, lon1, lat2, lon2) => {
  const R = 6371; // Radio de la Tierra en km
  const dLat = (lat2 - lat1) * (Math.PI / 180);
  const dLon = (lon2 - lon1) * (Math.PI / 180);
  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * (Math.PI / 180)) * Math.cos(lat2 * (Math.PI / 180)) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c; // Retorna distancia en km
};

// Lógica de filtrado por cercanía y favoritos
export const revisarOfertasCercanas = (miLat, miLng, ofertas, favoritos) => {
  const RADIO_NOTIFICACION = 0.5; // 500 metros
  
  return ofertas.filter(oferta => {
    const esInteresante = favoritos.some(fav => 
      oferta.producto.toLowerCase().includes(fav.toLowerCase())
    );

    if (!esInteresante) return false;

    const distancia = calcularDistancia(miLat, miLng, oferta.lat, oferta.lng);
    return distancia <= RADIO_NOTIFICACION;
  });
};

// CORRECCIÓN: Exportación de la lógica de validación del carrito
export const validateCartAddition = (cart, nuevoProducto, modoEntrega) => {
  // 1. Validar Local Único
  if (cart.length > 0 && cart[0].localId !== nuevoProducto.localId) {
    return { valid: false, msg: "Solo puedes pedir productos de un mismo local. Vacía el carrito para cambiar de comercio." };
  }

  // 2. Si es Retiro, saltamos límites de peso/cantidad de delivery
  if (modoEntrega === 'retiro') return { valid: true };

  // 3. Validar Cantidad máxima para delivery
  if (cart.length >= CART_LIMITS.MAX_ITEMS) {
    return { valid: false, msg: `Límite de delivery: máximo ${CART_LIMITS.MAX_ITEMS} productos.` };
  }

  // 4. Validar Peso máximo (mochila del repartidor)
  const pesoActual = cart.reduce((acc, p) => acc + (Number(p.peso) || 0), 0);
  const pesoNuevo = Number(nuevoProducto.peso) || 0;
  
  if (pesoActual + pesoNuevo > CART_LIMITS.MAX_WEIGHT_KG) {
    return { valid: false, msg: `El pedido excedería los ${CART_LIMITS.MAX_WEIGHT_KG}kg permitido para repartidores.` };
  }

  return { valid: true };
};
